import React, { useState } from 'react';
import {
  Text,
  View,
  TextInput,
  TouchableOpacity,
  ScrollView,
  StatusBar,
  Modal
} from 'react-native';
import * as FileSystem from 'expo-file-system/legacy';
import * as Print from 'expo-print';
import * as Sharing from 'expo-sharing';
import { styles } from './src/styles/styles';
import { Asset } from 'expo-asset';

  const logoBase64 = 'data:image/png;base64,';
  
 export default function App() {
  const [cliente, setCliente] = useState('');
  const [evento, setEvento] = useState('');
  const [dataEvento, setDataEvento] = useState('');
  const [horaEvento, setHoraEvento] = useState('');
  const [desconto, setDesconto] = useState('');
  const [itens, setItens] = useState([]);
  const [modalVisivel, setModalVisivel] = useState(false);
  const [itemSendoEditado, setItemSendoEditado] = useState(null);
  const [nomeItem, setNomeItem] = useState('');
  const [insumosItem, setInsumosItem] = useState('');
  const [custoItem, setCustoItem] = useState('');
  const [vendaItem, setVendaItem] = useState('');

  // Cálculos de Totais
  const somaItensVenda = itens.reduce((acc, item) => acc + item.venda, 0);
  const totalCusto = itens.reduce((acc, item) => acc + item.custo, 0);
  const valorDesconto = parseFloat(desconto.replace(',', '.')) || 0;
  const totalFinalVenda = somaItensVenda - valorDesconto;
  const lucroTotal = totalFinalVenda - totalCusto;

  const formatarData = (text) => {
    let cleaned = text.replace(/\D/g, '');
    if (cleaned.length > 8) cleaned = cleaned.substring(0, 8);
    if (cleaned.length > 4) return cleaned.replace(/^(\d{2})(\d{2})(\d{4}).*/, '$1/$2/$3');
    if (cleaned.length > 2) return cleaned.replace(/^(\d{2})(\d{0,2}).*/, '$1/$2');
    return cleaned;
  };

  const formatarHora = (text) => {
    let cleaned = text.replace(/\D/g, '');
    if (cleaned.length > 4) cleaned = cleaned.substring(0, 4);
    if (cleaned.length > 2) return cleaned.replace(/^(\d{2})(\d{0,2}).*/, '$1:$2');
    return cleaned;
  };

  const cssFolhaUnica = `
  <style>
    @page { size: A4; margin: 0; }
    body { 
      margin: 0; padding: 30px; 
      box-sizing: border-box; 
      height: 100vh; 
      display: flex; flex-direction: column; 
      font-family: 'Helvetica', sans-serif; color: #334155;
    }
    .header {
      display: flex; justify-content: space-between; align-items: center;
      border-bottom: 3px solid #8B221B; padding-bottom: 10px; margin-bottom: 20px;
    }
    .main-content { flex: 1; }
    
    /* Suporte para duas colunas no cliente se houver muitos itens */
    .tabela-wrapper {
      column-count: ${itens.length > 8 ? 2 : 1};
      column-gap: 20px;
    }

    table { width: 100%; border-collapse: collapse; margin-top: 10px; break-inside: avoid; }
    th { background: #8B221B; color: white; padding: 10px; font-size: 14px; text-transform: uppercase; }
    td { border: 1px solid #e2e8f0; padding: 10px; vertical-align: top; }
    
    .footer-box {
      margin-top: 20px; padding: 25px; 
      background: #8B221B; color: white; 
      border-radius: 15px; text-align: right;
    }
    .tech-info { text-align: center; color: #94a3b8; margin-top: 15px; font-size: 12px; }
    .logo-img { height: 80px; width: auto; }
  </style>
`;


  const obterHtmlEmpresa = () => `
  <html>
    <head>${cssFolhaUnica}</head>
    <body>
      <div class="header">
        <div>
          <h1 style="color: #8B221B; margin: 0; font-size: 24px;">Relatório Interno</h1>
          <p style="margin: 5px 0; color: #64748b;">Gestão de Custos e Margens</p>
        </div>
        <img src="${logoBase64}" class="logo-img" />
      </div>

      <div class="main-content">
        <p>Cliente: <strong>${cliente || '---'}</strong> | Evento: <strong>${evento || '---'}</strong> | Data: <strong>${dataEvento}</strong> às <strong>${horaEvento}</strong></p>
        <p></p>

        <table>
          <thead>
            <tr>
              <th style="text-align: left;">Itens / Insumos</th>
              <th>Custo</th>
              <th>Venda</th>
              <th>Lucro</th>
            </tr>
          </thead>
          <tbody>
            ${itens.map((item, index) => `
              <tr style="background: ${index % 2 === 0 ? '#ffffff' : '#f8fafc'};">
                <td>
                  <div style="margin-top: 1px; padding: 1px; font-weight: bold; font-size: 18px;">${item.nome}</div>
                  <div style="font-size: 15px; color: #64748b; font-style: italic;">${item.insumos || ''}</div>
                </td>
                <td style="text-align: center;">R$ ${item.custo.toFixed(2)}</td>
                <td style="text-align: center;">R$ ${item.venda.toFixed(2)}</td>
                <td style="text-align: center; font-weight: bold; color: #059669;">R$ ${(item.venda - item.custo).toFixed(2)}</td>
              </tr>
            `).join('')}
          </tbody>
        </table>
      </div>

      <div class="footer-box" style="background: #334155;"> <p style="margin: 0; opacity: 0.8;">Venda Bruta: R$ ${somaItensVenda.toFixed(2)}</p>
        <p style="margin: 5px 0; color: #fbbf24;">Descontos: - R$ ${valorDesconto.toFixed(2)}</p>
        <div style="border-top: 1px solid rgba(255,255,255,0.2); margin: 10px 0; padding-top: 10px;">
          <span style="font-size: 16px;">Lucro Líquido Final:</span>
          <h1 style="margin: 0; font-size: 32px; color: #34d399;">R$ ${lucroTotal.toFixed(2)}</h1>
        </div>
      </div>
      <div class="tech-info">Gerado internamente via MM10Sistemas</div>
    </body>
  </html>
`;

  const obterHtmlCliente = () => `
  <html>
    <head>${cssFolhaUnica}</head>
    <body>
      <div class="header">
        <div>
          <h1 style="color: #8B221B; margin: 0; font-size: 28px;">WK Eventos</h1>
          <p style="margin: 5px 0; color: #64748b;">Proposta Comercial</p>
        </div>
        <img src="${logoBase64}" class="logo-img" />
      </div>

      <div class="main-content">
        <p style="font-size: 18px;">Prezado(a) <strong>${cliente},</strong> conforme solicitado, segue proposta para o evento <strong>${evento}</strong> Data: <strong>${dataEvento}</strong> às <strong>${horaEvento}</strong>.</p>
        
        <div class="tabela-wrapper">
          <table>
            <thead>
              <tr>
                <th style="text-align: left;">Descrição dos Serviços</th>
                <th style="text-align: right;">Investimento</th>
              </tr>
            </thead>
            <tbody>
              ${itens.map((item, index) => `
                <tr style="background: ${index % 2 === 0 ? '#ffffff' : '#fdfaf9'};">
                  <td>
                    <div style="font-weight: bold; font-size: 16px; color: #211E1D;">
                      <span style="color: #EBD84B;">✔</span> ${item.nome}
                    </div>
                    ${item.insumos ? `<div style="font-size: 13px; color: #4a5667; margin-left: 22px; font-style: italic;">${item.insumos}</div>` : ''}
                  </td>
                  <td style="text-align: right; font-weight: bold; font-size: 15px;">R$ ${item.venda.toFixed(2)}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>
        </div>
      </div>

      <div class="footer-box">
        <p style="margin: 0; opacity: 0.8; font-size: 14px;">Subtotal: R$ ${somaItensVenda.toFixed(2)}</p>
        ${valorDesconto > 0 ? `<p style="margin: 5px 0; font-size: 16px; color: #EBD84B; font-weight: bold;">Bonificação/Desconto: - R$ ${valorDesconto.toFixed(2)}</p>` : ''}
        <div style="border-top: 1px solid rgba(255,255,255,0.2); margin: 10px 0; padding-top: 10px;">
          <span style="font-size: 18px;">Investimento Final:</span>
          <h1 style="margin: 0; font-size: 36px;">R$ ${totalFinalVenda.toFixed(2)}</h1>
        </div>
      </div>

      <div class="tech-info">
        WK Eventos | Válido por 30 dias | Gerado em ${new Date().toLocaleDateString('pt-BR')}<br/>
        <strong>TECNOLOGIA: MM10Sistemas | (41) 99761-8970</strong>
      </div>
    </body>
  </html>
`;

  const visualizarPdf = async (tipo) => {
    try {
      const html = tipo === 'cliente' ? obterHtmlCliente() : obterHtmlEmpresa();
      await Print.printAsync({ html });
    } catch (error) { console.error("Erro ao visualizar PDF:", error); }
  };

  const enviarPdf = async (tipo) => {
    try {
      const html = tipo === 'cliente' ? obterHtmlCliente() : obterHtmlEmpresa();
      const { uri } = await Print.printToFileAsync({ html });
      const nomeLimpo = cliente.trim().replace(/\s+/g, '_') || 'Sem_Nome';
      const sufixo = tipo === 'cliente' ? 'Proposta' : 'Relatorio_Interno';
      const nomeFinal = `${sufixo}_WK_Eventos_${nomeLimpo}.pdf`;
      const novoCaminho = `${FileSystem.cacheDirectory}${nomeFinal}`;
      await FileSystem.moveAsync({ from: uri, to: novoCaminho });
      await Sharing.shareAsync(novoCaminho);
    } catch (error) { console.error("Erro ao enviar PDF:", error); }
  };

  const salvarItem = () => {
    if (!nomeItem || !custoItem || !vendaItem) return;
    const dados = {
      nome: nomeItem,
      insumos: insumosItem,
      custo: parseFloat(custoItem.replace(',', '.')) || 0,
      venda: parseFloat(vendaItem.replace(',', '.')) || 0,
    };
    if (itemSendoEditado) {
      setItens(itens.map(i => i.id === itemSendoEditado ? { ...i, ...dados } : i));
    } else {
      setItens([...itens, { id: Math.random().toString(), ...dados }]);
    }
    setModalVisivel(false);
  };

  return (
    <View style={styles.container}>
      <StatusBar barStyle="light-content" />
      <View style={styles.header}><Text style={styles.title}>WK Eventos</Text></View>

      <ScrollView style={styles.form}>
        <Text style={styles.label}>Cliente</Text>
        <TextInput style={styles.input} placeholder="Nome do Cliente" placeholderTextColor="#94a3b8" value={cliente} onChangeText={setCliente} />

        <Text style={styles.label}>Evento</Text>
        <TextInput style={styles.input} placeholder="Tipo de Evento" placeholderTextColor="#94a3b8" value={evento} onChangeText={setEvento} />

        <View style={styles.row}>
          <View style={styles.flex2}>
            <Text style={styles.label}>Data</Text>
            <TextInput style={styles.input} placeholder="DD/MM/AAAA" placeholderTextColor="#94a3b8" value={dataEvento} onChangeText={t => setDataEvento(formatarData(t))} keyboardType="numeric" maxLength={10} />
          </View>
          <View style={styles.flex1}>
            <Text style={styles.label}>Hora</Text>
            <TextInput style={styles.input} placeholder="00:00" placeholderTextColor="#94a3b8" value={horaEvento} onChangeText={t => setHoraEvento(formatarHora(t))} keyboardType="numeric" maxLength={5} />
          </View>
        </View>

        <Text style={styles.sectionTitle}>Itens Adicionados ({itens.length})</Text>

        {itens.map((item) => (
          <View key={item.id} style={styles.itemCard}>
            <View style={styles.rowSpace}>
              <View style={styles.flex1}>
                <Text style={styles.itemTextNome}>{item.nome}</Text>
                {item.insumos ? <Text style={styles.itemTextInsumos}> {item.insumos}</Text> : null}
              </View>
              <View style={styles.actionButtons}>
                <TouchableOpacity onPress={() => {
                  setItemSendoEditado(item.id); setNomeItem(item.nome); setInsumosItem(item.insumos || '');
                  setCustoItem(item.custo.toString()); setVendaItem(item.venda.toString());
                  setModalVisivel(true);
                }}>
                  <Text style={styles.editBtn}>EDITAR</Text>
                </TouchableOpacity>
                <TouchableOpacity onPress={() => setItens(itens.filter(i => i.id !== item.id))}>
                  <Text style={styles.deleteBtn}>EXCLUIR</Text>
                </TouchableOpacity>
              </View>
            </View>
            <Text style={styles.itemTextValores}>Venda: R$ {item.venda.toFixed(2)} | <Text style={styles.custoBadge}>Custo: R$ {item.custo.toFixed(2)}</Text></Text>
          </View>
        ))}

        <TouchableOpacity style={styles.button} onPress={() => {
          setItemSendoEditado(null); setNomeItem(''); setInsumosItem(''); setCustoItem(''); setVendaItem('');
          setModalVisivel(true);
        }}>
          <Text style={styles.buttonText}>+ Adicionar Item / Tópico</Text>
        </TouchableOpacity>

        <View style={styles.descontoContainer}>
          <Text style={styles.label}>Desconto Especial (R$)</Text>
          <TextInput style={[styles.input, styles.inputDestaque]} placeholder="0,00" placeholderTextColor="#94a3b8" value={desconto} onChangeText={setDesconto} keyboardType="numeric" />
        </View>

        {itens.length > 0 && (
          <View style={styles.pdfSection}>
            <Text style={styles.pdfLabel}>RELATÓRIO INTERNO (WK):</Text>
            <View style={styles.row}>
              <TouchableOpacity style={[styles.buttonPDF, styles.btnVer]} onPress={() => visualizarPdf('empresa')}>
                <Text style={styles.buttonText}>Ver</Text>
              </TouchableOpacity>
              <TouchableOpacity style={styles.buttonPDF} onPress={() => enviarPdf('empresa')}>
                <Text style={styles.buttonText}>Gerar Relatório</Text>
              </TouchableOpacity>
            </View>

            <Text style={styles.pdfLabel}>PROPOSTA PARA CLIENTE:</Text>
            <View style={styles.row}>
              <TouchableOpacity style={[styles.buttonPDF, styles.btnVer]} onPress={() => visualizarPdf('cliente')}>
                <Text style={styles.buttonText}>Revisar</Text>
              </TouchableOpacity>
              <TouchableOpacity style={[styles.buttonPDF, styles.btnProposta]} onPress={() => enviarPdf('cliente')}>
                <Text style={styles.buttonText}>Enviar Proposta</Text>
              </TouchableOpacity>
            </View>
          </View>
        )}
      </ScrollView>

      <View style={styles.footer}>
        <View><Text style={styles.totalLabel}>Total Cliente</Text><Text style={styles.totalValue}>R$ {totalFinalVenda.toFixed(2)}</Text></View>
        <View style={styles.alignEnd}><Text style={styles.totalLabel}>Meu Lucro</Text><Text style={styles.lucroValue}>R$ {lucroTotal.toFixed(2)}</Text></View>
      </View>

      <Modal visible={modalVisivel} animationType="slide" transparent={true}>
        <View style={styles.modalContainer}>
          <View style={styles.modalContent}>
            <Text style={styles.modalTitle}>{itemSendoEditado ? 'Editar Item' : 'Novo Item / Tópico'}</Text>
            <TextInput style={styles.input} placeholder="Título do Tópico" placeholderTextColor="#94a3b8" value={nomeItem} onChangeText={setNomeItem} />
            <TextInput 
              style={[styles.input, styles.inputInsumos]} 
              placeholder="Insumos / Detalhes" placeholderTextColor="#94a3b8" multiline={true} 
              value={insumosItem} onChangeText={setInsumosItem} 
            />
            <TextInput style={styles.input} placeholder="Custo R$" placeholderTextColor="#94a3b8" keyboardType="numeric" value={custoItem} onChangeText={setCustoItem} />
            <TextInput style={styles.input} placeholder="Venda R$" placeholderTextColor="#94a3b8" keyboardType="numeric" value={vendaItem} onChangeText={setVendaItem} />
            <View style={styles.buttonGroup}>
              <TouchableOpacity style={styles.buttonCancel} onPress={() => setModalVisivel(false)}><Text style={styles.buttonText}>Sair</Text></TouchableOpacity>
              <TouchableOpacity style={styles.buttonSave} onPress={salvarItem}><Text style={styles.buttonText}>Salvar</Text></TouchableOpacity>
            </View>
          </View>
        </View>
      </Modal>
    </View>
  );
}